function solve(grid: number[][], x: number, y: number, k: number): number[][] {
    const submatrix: number[][] = [];
    for (let i = 0; i < k; i++) {
        const row = grid[x + i].slice(y, y + k);
        submatrix.push(row);
    }
    submatrix.reverse();
    for (let i = 0; i < k; i++) {
        const originalRow = grid[x + i];
        for (let j = 0; j < k; j++) {
            originalRow[y + j] = submatrix[i][j];
        }
    }
    return grid;
}
```

